// === CONFIG ===
// Actor IDs of the forms to offer in the transformation menu.
// Edit these to match actors in your world.
const ACTOR_IDS = [
  'actorId1',
  'actorId2',
];
const TITLE = 'Transform';
// === END CONFIG ===

// --- api.monsterFilter ---
// Predicate factories for filtering DS actors and tokens.
// Each returns a plain (actor) => boolean you can compose with && / ! / ||.
//
//   monsterFilter.keyword('abyssal')     -- actor has the given keyword
//   monsterFilter.organization('minion') -- actor organization (minion/horde/solo/boss/leader)
//   monsterFilter.level(3)               -- actor is exactly level 3
//   monsterFilter.sameLevel(token)       -- matches the level of a token (captured at call time)
//   monsterFilter.type('npc')            -- actor.type matches
//   monsterFilter.onActor(fn)            -- wraps an actor predicate to filter Token objects
//
// Example -- target any non-minion abyssal token, offer same-level abyssal minions:
//
//   const { monsterFilter: f } = api;
//   const _abyssal = f.keyword('abyssal');
//   const _minion  = f.organization('minion');
//   await api.transform(
//     f.onActor(a => _abyssal(a) && !_minion(a)),
//     tok => game.actors
//       .filter(a => a.type==='npc' && _abyssal(a) && _minion(a) && f.sameLevel(tok)(a))
//       .sort((a,b) => a.name.localeCompare(b.name)),
//     'Abyssal Devolution',
//     { color: 0x9900cc, hint: 'Click a token to devolve.' }
//   );

const api    = game.modules.get('draw-steel-combat-tools-vicroms')?.api;
const actors = ACTOR_IDS.map(id => game.actors.get(id)).filter(Boolean);
if (!actors.length) { ui.notifications.warn('No valid actors found. Check ACTOR_IDS in the macro.'); return; }

await api?.transform(null, actors, TITLE);
